# -*- coding: utf-8 -*-
# =============================================================================
# м»ҙнҸ¬л„ҢнҠё к°ңмҡ”: 04 Workflow Skill л“ұлЎқ кІ°кіј м •к·ңнҷ”кё°
# м—ӯн• : LLM нӣ„ліҙ JSONмқ„ м ҖмһҘ к°ҖлҠҘн•ң Workflow Skill л¬ём„ңлЎң м •к·ңнҷ”н•ҳкі  мӢӨн–ү кі„м•Ҫмқ„ кІ°м •лЎ м ҒмңјлЎң кІҖмҰқн•©лӢҲлӢӨ.
# мЈјмҡ” мһ…л Ҙ: мҡ”мІӯ нҺҳмқҙлЎңл“ң(payload), LLM мқ‘лӢө(llm_response)
# мЈјмҡ” м¶ңл Ҙ: нҺҳмқҙлЎңл“ң м¶ңл Ҙ(payload_out)
# мІҳлҰ¬ нқҗлҰ„: JSON нҢҢмӢұ -> н•„л“ң м •к·ңнҷ” -> ToolВ·лӢЁкі„В·dependencyВ·handoff кІҖмҰқ -> м ҖмһҘ нӣ„ліҙ мғқм„ұ
# мң м§ҖліҙмҲҳ нҸ¬мқёнҠё: LLM м¶ңл Ҙмқҙ к·ңм№ҷмқ„ мң„л°ҳн•ҳл©ҙ мһҗлҸҷ ліҙм •мңјлЎң мҲЁкё°м§Җ м•Ҡкі  errorsм—җ кё°лЎқн•ҙ Writerм—җм„ң м°ЁлӢЁн•©лӢҲлӢӨ.
# =============================================================================

from __future__ import annotations

import json
import re
from copy import deepcopy
from typing import Any

from lfx.custom.custom_component.component import Component
from lfx.io import DataInput, MessageTextInput, Output
from lfx.schema.data import Data

SECTION = "workflow_skills"
MAX_STEPS = 4
MAX_STEP_QUESTION_CHARS = 4000
MAX_WORKFLOW_PAYLOAD_BYTES = 32768
WORKFLOW_KEY_PATTERN = re.compile(r"^[a-z][a-z0-9_-]{2,63}$")
STEP_ID_PATTERN = re.compile(r"^[A-Za-z][A-Za-z0-9_-]{0,63}$")
ALLOWED_TOOL_NAMES = {
    "run_data_analysis",
    "run_metadata_qa",
    "run_visualization",
    "save_domain_metadata",
    "save_table_catalog_metadata",
    "save_main_flow_filter_metadata",
}
ALLOWED_HANDOFFS = {"none", "result_ref"}
ALLOWED_ON_ERROR = {"stop", "continue"}
RESULT_REF_PRODUCERS = {"run_data_analysis"}
RESULT_REF_CONSUMERS = {"run_data_analysis", "run_visualization"}


# мЈјмҡ” н•ЁмҲҳ: LLM мқ‘лӢөм—җм„ң Workflow Skill нӣ„ліҙ н•ҳлӮҳлҘј м¶”м¶ңн•ҳкі  лӘЁл“  мӢӨн–ү к·ңм№ҷ мң„л°ҳмқ„ мҳӨлҘҳлЎң кё°лЎқн•©лӢҲлӢӨ.
def normalize_authoring(payload_value: Any, llm_response: Any) -> dict[str, Any]:
    payload = _payload(payload_value)
    parsed = _json(llm_response)
    raw_items = _raw_items(parsed)
    errors = []
    if not parsed:
        errors.append({"type": "llm_response_parse_error", "message": "LLM л“ұлЎқ мқ‘лӢөмқ„ JSON objectлЎң н•ҙм„қн•ҳм§Җ лӘ»н–ҲмҠөлӢҲлӢӨ."})
    if len(raw_items) > 1:
        errors.append({"type": "multiple_workflows_not_allowed", "message": "н•ң мҡ”мІӯм—җм„ңлҠ” Workflow Skillмқ„ н•ң кұҙл§Ң л“ұлЎқн•  мҲҳ мһҲмҠөлӢҲлӢӨ."})
    items = []
    for index, raw in enumerate(raw_items[:1]):
        if not isinstance(raw, dict):
            errors.append({"type": "invalid_workflow_item", "message": f"items[{index}]к°Җ objectк°Җ м•„лӢҷлӢҲлӢӨ.", "index": index})
            continue
        item = _normalize_item(raw)
        errors.extend(validate_workflow_item(item, index))
        items.append(item)
    refinement = _refinement(payload, parsed)
    if not items and not refinement["needs_more_input"] and not errors:
        errors.append({"type": "no_valid_workflow", "message": "м ҖмһҘн•  Workflow Skill нӣ„ліҙк°Җ мғқм„ұлҗҳм§Җ м•Ҡм•ҳмҠөлӢҲлӢӨ."})
    payload["items"] = items
    payload["refinement"] = refinement
    payload.setdefault("errors", []).extend(errors)
    payload.setdefault("trace", {})["generated_items_preview"] = [
        {
            "key": str(item.get("key") or ""),
            "display_name": str(_dict(item.get("payload")).get("display_name") or ""),
            "step_count": len(_list(_dict(item.get("payload")).get("steps"))),
            "tool_names": [str(_dict(step).get("tool_name") or "") for step in _list(_dict(item.get("payload")).get("steps"))],
        }
        for item in items
    ]
    payload["trace"]["workflow_contract"] = {
        "max_steps": MAX_STEPS,
        "allowed_tools": sorted(ALLOWED_TOOL_NAMES),
        "result_ref_producers": sorted(RESULT_REF_PRODUCERS),
        "result_ref_consumers": sorted(RESULT_REF_CONSUMERS),
    }
    return payload


# мЈјмҡ” н•ЁмҲҳ: м •к·ңнҷ”лҗң Workflow Skillмқҳ н•„мҲҳ н•„л“ңмҷҖ мҲңм°Ё мӢӨн–ү кі„м•Ҫмқ„ кІ°м •лЎ м ҒмңјлЎң кІҖмӮ¬н•©лӢҲлӢӨ.
def validate_workflow_item(item: dict[str, Any], item_index: int = 0) -> list[dict[str, Any]]:
    errors: list[dict[str, Any]] = []
    key = str(item.get("key") or "")
    item_payload = _dict(item.get("payload"))
    steps = [_dict(step) for step in _list(item_payload.get("steps"))]
    if item.get("section") != SECTION:
        errors.append(_issue("invalid_section", f"sectionмқҖ {SECTION}мқҙм–ҙм•ј н•©лӢҲлӢӨ.", item_index=item_index, key=key))
    if not WORKFLOW_KEY_PATTERN.fullmatch(key):
        errors.append(_issue("invalid_workflow_key", "workflow keyлҠ” мҳҒл¬ё мҶҢл¬ёмһҗлЎң мӢңмһ‘н•ҳлҠ” 3~64мһҗмқҳ мҳҒл¬ё мҶҢл¬ёмһҗВ·мҲ«мһҗВ·л°‘мӨ„В·н•ҳмқҙн”Ҳмқҙм–ҙм•ј н•©лӢҲлӢӨ.", item_index=item_index, key=key))
    if not str(item_payload.get("display_name") or "").strip():
        errors.append(_issue("missing_display_name", "Workflow н‘ңмӢң мқҙлҰ„мқҙ м—ҶмҠөлӢҲлӢӨ.", item_index=item_index, key=key))
    if not str(item_payload.get("description") or "").strip():
        errors.append(_issue("missing_description", "Workflow м„ӨлӘ…мқҙ м—ҶмҠөлӢҲлӢӨ.", item_index=item_index, key=key))
    if not steps:
        errors.append(_issue("missing_steps", "Workflowм—җлҠ” мӢӨн–ү лӢЁкі„к°Җ н•ң к°ң мқҙмғҒ н•„мҡ”н•©лӢҲлӢӨ.", item_index=item_index, key=key))
    if len(steps) > MAX_STEPS:
        errors.append(_issue("too_many_steps", f"Workflow мӢӨн–ү лӢЁкі„лҠ” мөңлҢҖ {MAX_STEPS}к°ңмһ…лӢҲлӢӨ.", item_index=item_index, key=key, step_count=len(steps)))
    seen_step_ids: set[str] = set()
    step_by_id: dict[str, dict[str, Any]] = {}
    for step_index, step in enumerate(steps):
        step_id = str(step.get("step_id") or "")
        tool_name = str(step.get("tool_name") or "")
        depends_on = [str(value) for value in _list(step.get("depends_on"))]
        handoff = str(step.get("handoff") or "")
        location = {"item_index": item_index, "key": key, "step_index": step_index, "step_id": step_id}
        if not STEP_ID_PATTERN.fullmatch(step_id):
            errors.append(_issue("invalid_step_id", "step_idлҠ” мҳҒл¬ёмһҗлЎң мӢңмһ‘н•ҳлҠ” 1~64мһҗмқҳ мҳҒл¬ёВ·мҲ«мһҗВ·л°‘мӨ„В·н•ҳмқҙн”Ҳмқҙм–ҙм•ј н•©лӢҲлӢӨ.", **location))
        if step_id in seen_step_ids:
            errors.append(_issue("duplicate_step_id", "к°ҷмқҖ Workflow м•Ҳм—җм„ң step_idк°Җ мӨ‘ліөлҗҳм—ҲмҠөлӢҲлӢӨ.", **location))
        if tool_name not in ALLOWED_TOOL_NAMES:
            errors.append(_issue("unsupported_tool", f"м§Җмӣҗн•ҳм§Җ м•ҠлҠ” Toolмһ…лӢҲлӢӨ: {tool_name}", **location))
        question = str(step.get("question") or "").strip()
        if not question:
            errors.append(_issue("missing_step_question", "к°Ғ лӢЁкі„м—җлҠ” мӢӨн–үн•  questionмқҙ н•„мҡ”н•©лӢҲлӢӨ.", **location))
        elif len(question) > MAX_STEP_QUESTION_CHARS:
            errors.append(_issue("step_question_too_long", f"лӢЁкі„ questionмқҖ {MAX_STEP_QUESTION_CHARS}мһҗлҘј мҙҲкіјн•  мҲҳ м—ҶмҠөлӢҲлӢӨ.", **location))
        if handoff not in ALLOWED_HANDOFFS:
            errors.append(_issue("invalid_handoff", "handoffлҠ” none лҳҗлҠ” result_refм—¬м•ј н•©лӢҲлӢӨ.", **location))
        if str(step.get("on_error") or "") not in ALLOWED_ON_ERROR:
            errors.append(_issue("invalid_on_error", "on_errorлҠ” stop лҳҗлҠ” continueм—¬м•ј н•©лӢҲлӢӨ.", **location))
        if len(depends_on) != len(set(depends_on)):
            errors.append(_issue("duplicate_dependency", "depends_onм—җ к°ҷмқҖ step_idк°Җ мӨ‘ліөлҗҳм—ҲмҠөлӢҲлӢӨ.", **location))
        for dependency in depends_on:
            if dependency not in seen_step_ids:
                errors.append(_issue("dependency_not_prior", f"depends_onмқҖ м•һм—җм„ң м •мқҳлҗң step_idл§Ң мӮ¬мҡ©н•  мҲҳ мһҲмҠөлӢҲлӢӨ: {dependency}", dependency=dependency, **location))
        if step_index == 0 and depends_on:
            errors.append(_issue("first_step_dependency_not_allowed", "мІ« лӢЁкі„мқҳ depends_onмқҖ л№Ҳ л°°м—ҙмқҙм–ҙм•ј н•©лӢҲлӢӨ.", **location))
        if step_index == 0 and handoff != "none":
            errors.append(_issue("first_step_handoff_not_allowed", "мІ« лӢЁкі„мқҳ handoffлҠ” noneмқҙм–ҙм•ј н•©лӢҲлӢӨ.", **location))
        if handoff == "result_ref":
            if len(depends_on) != 1:
                errors.append(_issue("ambiguous_result_ref_handoff", "result_ref handoffм—җлҠ” dependencyк°Җ м •нҷ•нһҲ н•ң к°ң н•„мҡ”н•©лӢҲлӢӨ.", **location))
            elif depends_on[0] in step_by_id:
                source_tool = str(step_by_id[depends_on[0]].get("tool_name") or "")
                if source_tool not in RESULT_REF_PRODUCERS:
                    errors.append(_issue("result_ref_source_not_supported", f"{source_tool}мқҖ result_refлҘј мғқм„ұн•ҳм§Җ м•ҠмҠөлӢҲлӢӨ.", dependency=depends_on[0], **location))
            if tool_name not in RESULT_REF_CONSUMERS:
                errors.append(_issue("result_ref_target_not_supported", f"{tool_name}мқҖ upstream_result_ref мһ…л Ҙмқ„ м§Җмӣҗн•ҳм§Җ м•ҠмҠөлӢҲлӢӨ.", **location))
        seen_step_ids.add(step_id)
        step_by_id[step_id] = step
    payload_bytes = len(json.dumps(item_payload, ensure_ascii=False, separators=(",", ":")).encode("utf-8"))
    if payload_bytes > MAX_WORKFLOW_PAYLOAD_BYTES:
        errors.append(
            _issue(
                "workflow_payload_too_large",
                f"Workflow Skill payloadлҠ” UTF-8 {MAX_WORKFLOW_PAYLOAD_BYTES}л°”мқҙнҠёлҘј мҙҲкіјн•  мҲҳ м—ҶмҠөлӢҲлӢӨ.",
                item_index=item_index,
                key=key,
                payload_bytes=payload_bytes,
            )
        )
    return _unique_errors(errors)


# н•ЁмҲҳ м„ӨлӘ…: `_raw_items()`лҠ” н—Ҳмҡ©лҗң LLM мқ‘лӢө ліҖнҳ•м—җм„ң Workflow нӣ„ліҙ лӘ©лЎқмқ„ кәјлғ…лӢҲлӢӨ.
def _raw_items(parsed: dict[str, Any]) -> list[Any]:
    if isinstance(parsed.get("items"), list):
        return parsed["items"]
    if isinstance(parsed.get("workflow"), dict):
        return [parsed["workflow"]]
    if isinstance(parsed.get("workflows"), list):
        return parsed["workflows"]
    if parsed.get("workflow_key") or parsed.get("key"):
        return [parsed]
    return []


# н•ЁмҲҳ м„ӨлӘ…: `_normalize_item()`мқҖ LLMмқҳ м—¬лҹ¬ н•„л“ң лі„м№ӯмқ„ кі м •лҗң MongoDB Workflow Skill л¬ём„ң нҳ•нғңлЎң л°”кҝүлӢҲлӢӨ.
def _normalize_item(raw: dict[str, Any]) -> dict[str, Any]:
    raw_payload = _dict(raw.get("payload"))
    key = _text(raw.get("key") or raw.get("workflow_key") or raw_payload.get("workflow_key"))
    display_name = _text(raw_payload.get("display_name") or raw_payload.get("title") or raw.get("display_name") or raw.get("title"))
    description = _text(raw_payload.get("description") or raw.get("description"))
    steps_source = raw_payload.get("steps") if isinstance(raw_payload.get("steps"), list) else raw.get("steps")
    steps = [_normalize_step(step, index) for index, step in enumerate(_list(steps_source)) if isinstance(step, dict)]
    return {
        "section": SECTION,
        "key": key,
        "status": "inactive" if str(raw.get("status") or "").strip().lower() == "inactive" else "active",
        "payload": {
            "display_name": display_name,
            "description": description,
            "aliases": _string_list(raw_payload.get("aliases") or raw.get("aliases"), 20, 120),
            "intent_examples": _string_list(raw_payload.get("intent_examples") or raw.get("intent_examples"), 20, 500),
            "keywords": _string_list(raw_payload.get("keywords") or raw.get("keywords"), 30, 80),
            "excluded_keywords": _string_list(raw_payload.get("excluded_keywords") or raw.get("excluded_keywords"), 30, 80),
            "priority": _bounded_int(raw_payload.get("priority", raw.get("priority", 100)), 100, -1000, 1000),
            "steps": steps,
        },
    }


# н•ЁмҲҳ м„ӨлӘ…: `_normalize_step()`мқҖ лӢЁкі„ н•„л“ңлҘј 08 Workflow Orchestratorк°Җ мҶҢл№„н•ҳлҠ” кі м • step кі„м•ҪмңјлЎң ліҖнҷҳн•©лӢҲлӢӨ.
def _normalize_step(raw: dict[str, Any], index: int) -> dict[str, Any]:
    del index
    dependencies = raw.get("depends_on")
    if isinstance(dependencies, str):
        dependencies = [dependencies]
    return {
        "step_id": _text(raw.get("step_id") or raw.get("id")),
        "tool_name": _text(raw.get("tool_name") or raw.get("tool")).lower(),
        "question": _text(raw.get("question")),
        "depends_on": _string_list(dependencies, MAX_STEPS, 64),
        "handoff": _text(raw.get("handoff") or "none").lower(),
        "on_error": _text(raw.get("on_error") or "stop").lower(),
    }


# н•ЁмҲҳ м„ӨлӘ…: `_refinement()`мқҖ LLMмқҳ ліҙмҷ„ н•„мҡ” м •ліҙмҷҖ кё°мЎҙ ліҙм • мғҒнғңлҘј мҶҗмӢӨ м—Ҷмқҙ н•©м№©лӢҲлӢӨ.
def _refinement(payload: dict[str, Any], parsed: dict[str, Any]) -> dict[str, Any]:
    current = deepcopy(_dict(payload.get("refinement")))
    supplied = _dict(parsed.get("refinement"))
    missing = _string_list(supplied.get("missing_information") or parsed.get("missing_information"), 20, 500)
    assumptions = _string_list(supplied.get("assumptions") or parsed.get("assumptions"), 20, 500)
    return {
        "refined_text": _text(supplied.get("refined_text") or current.get("refined_text")),
        "needs_more_input": _truthy(supplied.get("needs_more_input", parsed.get("needs_more_input"))) or bool(missing),
        "missing_information": missing,
        "assumptions": assumptions,
    }


# н•ЁмҲҳ м„ӨлӘ…: `_issue()`лҠ” кІҖмҰқ мҳӨлҘҳлҘј typeВ·messageмҷҖ мң„м№ҳ м •ліҙк°Җ мһҲлҠ” н‘ңмӨҖ dictлЎң л§Ңл“ӯлӢҲлӢӨ.
def _issue(error_type: str, message: str, **details: Any) -> dict[str, Any]:
    return {"type": error_type, "message": message, **details}


# н•ЁмҲҳ м„ӨлӘ…: `_unique_errors()`лҠ” к°ҷмқҖ мң„м№ҳм—җм„ң л°ҳліөлҗң мҳӨлҘҳлҘј мөңмҙҲ мҲңм„ңлҢҖлЎң н•ҳлӮҳл§Ң лӮЁк№ҒлӢҲлӢӨ.
def _unique_errors(values: list[dict[str, Any]]) -> list[dict[str, Any]]:
    result = []
    seen = set()
    for value in values:
        marker = (value.get("type"), value.get("key"), value.get("step_id"), value.get("dependency"), value.get("message"))
        if marker not in seen:
            seen.add(marker)
            result.append(value)
    return result


# н•ЁмҲҳ м„ӨлӘ…: `_string_list()`лҠ” л¬ёмһҗм—ҙ лӘ©лЎқмқ„ кіөл°ұВ·мӨ‘ліөВ·кёёмқҙ м ңн•ңмқҙ м Ғмҡ©лҗң м•Ҳм „н•ң лӘ©лЎқмңјлЎң м •лҰ¬н•©лӢҲлӢӨ.
def _string_list(value: Any, item_limit: int, text_limit: int) -> list[str]:
    raw = value if isinstance(value, list) else []
    result = []
    seen = set()
    for item in raw:
        text = _text(item)
        text = text[:text_limit]
        marker = text.casefold()
        if text and marker not in seen:
            seen.add(marker)
            result.append(text)
        if len(result) >= item_limit:
            break
    return result


# н•ЁмҲҳ м„ӨлӘ…: `_bounded_int()`лҠ” priority к°’мқ„ н—Ҳмҡ© лІ”мң„ м•Ҳмқҳ м •мҲҳлЎң м ңн•ңн•©лӢҲлӢӨ.
def _bounded_int(value: Any, default: int, minimum: int, maximum: int) -> int:
    try:
        return max(minimum, min(maximum, int(value)))
    except Exception:
        return default


# н•ЁмҲҳ м„ӨлӘ…: `_truthy()`лҠ” LLMмқҳ bool лҳҗлҠ” л¬ёмһҗм—ҙ н‘ңнҳ„мқ„ м•Ҳм „н•ң м°ёВ·кұ°м§“ к°’мңјлЎң н•ҙм„қн•©лӢҲлӢӨ.
def _truthy(value: Any) -> bool:
    return value is True or str(value or "").strip().lower() in {"1", "true", "yes", "y", "on"}


# н•ЁмҲҳ м„ӨлӘ…: `_text()`лҠ” Message лҳҗлҠ” мқјл°ҳ к°’мқ„ м•һл’Ө кіөл°ұмқҙ м—ҶлҠ” л¬ёмһҗм—ҙлЎң ліҖнҷҳн•©лӢҲлӢӨ.
def _text(value: Any) -> str:
    text = getattr(value, "text", value)
    return "" if text is None else str(text).strip()


# н•ЁмҲҳ м„ӨлӘ…: `_payload()`лҠ” Langflow Data лҳҗлҠ” dictм—җм„ң нӣ„мҶҚ ліҖкІҪм—җ м•Ҳм „н•ң ліөмӮ¬ліёмқ„ кәјлғ…лӢҲлӢӨ.
def _payload(value: Any) -> dict[str, Any]:
    data = getattr(value, "data", value)
    return deepcopy(data) if isinstance(data, dict) else {}


# н•ЁмҲҳ м„ӨлӘ…: `_json()`мқҖ MessageВ·dictВ·Markdown JSON мқ‘лӢөм—җм„ң object н•ҳлӮҳлҘј м•Ҳм „н•ҳкІҢ нҢҢмӢұн•©лӢҲлӢӨ.
def _json(value: Any) -> dict[str, Any]:
    if isinstance(value, dict):
        return deepcopy(value)
    text = _text(value)
    fence = re.search(r"```(?:json)?\s*(\{.*\})\s*```", text, re.DOTALL | re.IGNORECASE)
    if fence:
        text = fence.group(1)
    elif "{" in text and "}" in text:
        text = text[text.find("{") : text.rfind("}") + 1]
    try:
        parsed = json.loads(text)
    except Exception:
        return {}
    return parsed if isinstance(parsed, dict) else {}


# н•ЁмҲҳ м„ӨлӘ…: `_dict()`лҠ” к°’мқҙ dictмқј л•Ңл§Ң к·ёлҢҖлЎң л°ҳнҷҳн•ҳкі  лӢӨлҘё нҳ•мӢқмқҖ л№Ҳ dictлЎң л°”кҝүлӢҲлӢӨ.
def _dict(value: Any) -> dict[str, Any]:
    return value if isinstance(value, dict) else {}


# н•ЁмҲҳ м„ӨлӘ…: `_list()`лҠ” к°’мқҙ listмқј л•Ңл§Ң к·ёлҢҖлЎң л°ҳнҷҳн•ҳкі  лӢӨлҘё нҳ•мӢқмқҖ л№Ҳ лӘ©лЎқмңјлЎң л°”кҝүлӢҲлӢӨ.
def _list(value: Any) -> list[Any]:
    return value if isinstance(value, list) else []


# Langflow м»ҙнҸ¬л„ҢнҠё нҒҙлһҳмҠӨ: LLM мҙҲм•Ҳмқ„ кІ°м •лЎ м ҒмңјлЎң кІҖмҰқн•ң Workflow Skill нҺҳмқҙлЎңл“ңлЎң ліҖнҷҳн•©лӢҲлӢӨ.
