SECTION = "workflow_skills"
DEFAULT_DATABASE = "datagov"
DEFAULT_COLLECTION = "agent_v4_workflow_skills"
ALLOWED_ACTIONS = {"skip", "merge", "replace", "create_new"}
ALLOWED_TOOLS = {
