WORKFLOW_KEY_PATTERN = re.compile(r"^[a-z][a-z0-9_-]{2,63}$")
STEP_ID_PATTERN = re.compile(r"^[A-Za-z][A-Za-z0-9_-]{0,63}$")
SECRET_PATTERNS = ("password", "passwd", "token", "secret", "api_key", "apikey", "authorization", "credential", "access_key", "private_key", "cookie")


# мЈјмҡ” н•ЁмҲҳ: мғҒмң„ кІҖмҰқкіј duplicate м •мұ…мқ„ м Ғмҡ©н•ҙ dry-run лҳҗлҠ” мӢӨм ң MongoDB м ҖмһҘ кІ°кіјлҘј л§Ңл“ӯлӢҲлӢӨ.
def review_and_write(
    payload_value: Any,
    review_response: Any = "",
    mongo_uri: str = "",
    mongo_database: str = "",
    collection_name: str = "",
) -> dict[str, Any]:
    del review_response
    payload = _payload(payload_value)
    action = _duplicate_action(payload)
    dry_run = bool(_dict(payload.get("request")).get("dry_run", True))
    review = _deterministic_review(payload, action)
    payload["review"] = review
    if not review["ready_to_save"]:
        needs_input = bool(review["supplement_requests"])
        payload["write_result"] = {
            "success": False,
            "ready_to_save": False,
            "status": "needs_input" if needs_input else "error",
            "dry_run": dry_run,
            "saved_count": 0,
            "would_save_count": 0,
            "skipped_count": 0,
            "operation_by_key": [],
            "message": "м¶”к°Җ м •ліҙк°Җ н•„мҡ”н•ҙ м ҖмһҘн•ҳм§Җ м•Ҡм•ҳмҠөлӢҲлӢӨ." if needs_input else "Workflow Skill кІҖмҰқмқ„ нҶөкіјн•ҳм§Җ лӘ»н•ҙ м ҖмһҘн•ҳм§Җ м•Ҡм•ҳмҠөлӢҲлӢӨ.",
            "errors": deepcopy(review["errors"]),
            "supplement_requests": deepcopy(review["supplement_requests"]),
        }
    elif dry_run:
        payload["write_result"] = _dry_run_result(payload, action)
    else:
        payload["write_result"] = _write_to_mongodb(payload, action, mongo_uri, mongo_database, collection_name)
    return payload


# н•ЁмҲҳ м„ӨлӘ…: `_deterministic_review()`лҠ” мғҒмң„ мҳӨлҘҳВ·н•„мҲҳ мҠӨнӮӨл§ҲВ·л№„л°Җ н•„л“ңВ·мӨ‘ліө мЎ°нҡҢ мғҒнғңлҘј м ҖмһҘ м°ЁлӢЁ мЎ°кұҙмңјлЎң кІҖмӮ¬н•©лӢҲлӢӨ.
def _deterministic_review(payload: dict[str, Any], action: str) -> dict[str, Any]:
    refinement = deepcopy(_dict(payload.get("refinement")))
    errors = _unique_errors(_list(payload.get("errors")))
    missing = [str(item).strip() for item in _list(refinement.get("missing_information")) if str(item or "").strip()]
    if bool(refinement.get("needs_more_input")) and not missing:
        missing.append("Workflow мӢӨн–ү мҲңм„ңлҘј нҷ•м •н•  мҲҳ мһҲлҸ„лЎқ мӣҗл¬ёмқ„ ліҙмҷ„н•ҙ мЈјм„ёмҡ”.")
    items = [_dict(item) for item in _list(payload.get("items")) if isinstance(item, dict)]
    if len(items) != 1:
        errors.append({"type": "workflow_item_count_error", "message": "н•ң лІҲм—җ Workflow Skill н•ң кұҙл§Ң м ҖмһҘн•  мҲҳ мһҲмҠөлӢҲлӢӨ."})
    for item in items:
        errors.extend(_validate_item(item))
        for path in _secret_paths(item):
            errors.append({"type": "credential_field_forbidden", "message": f"credential/secret н•„л“ңлҠ” м ҖмһҘн•  мҲҳ м—ҶмҠөлӢҲлӢӨ: {path}", "field": path, "key": item.get("key", "")})
    lookup = _dict(_dict(payload.get("trace")).get("duplicate_lookup"))
    if action != "create_new" and lookup.get("status") in {"error", "skipped"} and int(lookup.get("combined_count") or 0) == 0:
        errors.append(
            {
                "type": "identity_lookup_unavailable",
                "message": "кё°мЎҙ Workflow Skill мЎ°нҡҢлҘј мҷ„лЈҢн•ҳм§Җ лӘ»н•ҙ мӨ‘ліө м—¬л¶ҖлҘј нҷ•м •н•  мҲҳ м—ҶмҠөлӢҲлӢӨ.",
                "lookup_errors": deepcopy(_list(lookup.get("errors"))),
            }
        )
    resolution = _match_resolution(payload)
    if resolution["status"] == "ambiguous" and action != "create_new":
        errors.append(
            {
                "type": "ambiguous_replace_target" if action == "replace" else "ambiguous_identity_target",
                "message": "мң мӮ¬н•ң кё°мЎҙ Workflow Skillмқҙ м—¬лҹ¬ кұҙмқҙлқј м ҖмһҘ лҢҖмғҒмқ„ н•ҳлӮҳлЎң нҷ•м •н•  мҲҳ м—ҶмҠөлӢҲлӢӨ.",
                "existing_candidate_keys": deepcopy(resolution.get("candidate_keys", [])),
            }
        )
    errors = _unique_errors(errors)
    ready = len(items) == 1 and not errors and not missing
    return {
        "ready_to_save": ready,
        "item_reviews": [{"key": str(item.get("key") or ""), "ready_to_save": ready, "warnings": [], "errors": deepcopy(errors)} for item in items],
        "errors": errors,
        "supplement_requests": missing,
        "assumptions": [str(item).strip() for item in _list(refinement.get("assumptions")) if str(item or "").strip()],
        "refinement": refinement,
    }


# н•ЁмҲҳ м„ӨлӘ…: `_validate_item()`мқҖ Writer кІҪкі„м—җм„ң Workflow Skill н•өмӢ¬ мҠӨнӮӨл§ҲлҘј н•ң лІҲ лҚ” кІҖмӮ¬н•©лӢҲлӢӨ.
def _validate_item(item: dict[str, Any]) -> list[dict[str, Any]]:
    errors = []
    key = str(item.get("key") or "")
    payload = _dict(item.get("payload"))
    steps = [_dict(step) for step in _list(payload.get("steps"))]
    if item.get("section") != SECTION:
        errors.append({"type": "invalid_section", "message": f"sectionмқҖ {SECTION}мқҙм–ҙм•ј н•©лӢҲлӢӨ.", "key": key})
    if not WORKFLOW_KEY_PATTERN.fullmatch(key):
        errors.append({"type": "invalid_workflow_key", "message": "мң нҡЁн•ң workflow keyк°Җ м—ҶмҠөлӢҲлӢӨ.", "key": key})
    if not str(payload.get("display_name") or "").strip() or not str(payload.get("description") or "").strip():
        errors.append({"type": "missing_workflow_description", "message": "display_nameкіј descriptionмқҙ лӘЁл‘җ н•„мҡ”н•©лӢҲлӢӨ.", "key": key})
    if not 1 <= len(steps) <= 4:
        errors.append({"type": "invalid_step_count", "message": "мӢӨн–ү лӢЁкі„лҠ” 1~4к°ңм—¬м•ј н•©лӢҲлӢӨ.", "key": key})
    seen = set()
    by_id = {}
    for index, step in enumerate(steps):
        step_id = str(step.get("step_id") or "")
        tool_name = str(step.get("tool_name") or "")
        dependencies = [str(value) for value in _list(step.get("depends_on"))]
        if not STEP_ID_PATTERN.fullmatch(step_id) or step_id in seen:
            errors.append({"type": "invalid_or_duplicate_step_id", "message": "step_id нҳ•мӢқмқҙ мһҳлӘ»лҗҳм—Ҳкұ°лӮҳ мӨ‘ліөлҗҳм—ҲмҠөлӢҲлӢӨ.", "key": key, "step_id": step_id})
        if tool_name not in ALLOWED_TOOLS:
            errors.append({"type": "unsupported_tool", "message": f"м§Җмӣҗн•ҳм§Җ м•ҠлҠ” Toolмһ…лӢҲлӢӨ: {tool_name}", "key": key, "step_id": step_id})
        question = str(step.get("question") or "").strip()
        if not question:
            errors.append({"type": "missing_step_question", "message": "лӢЁкі„ questionмқҙ л№„м–ҙ мһҲмҠөлӢҲлӢӨ.", "key": key, "step_id": step_id})
        elif len(question) > MAX_STEP_QUESTION_CHARS:
            errors.append({"type": "step_question_too_long", "message": f"лӢЁкі„ questionмқҖ {MAX_STEP_QUESTION_CHARS}мһҗлҘј мҙҲкіјн•  мҲҳ м—ҶмҠөлӢҲлӢӨ.", "key": key, "step_id": step_id})
        if any(dependency not in seen for dependency in dependencies):
            errors.append({"type": "dependency_not_prior", "message": "depends_onмқҖ м•һм—җм„ң м •мқҳлҗң step_idл§Ң мӮ¬мҡ©н•  мҲҳ мһҲмҠөлӢҲлӢӨ.", "key": key, "step_id": step_id})
        handoff = str(step.get("handoff") or "")
        if handoff not in {"none", "result_ref"}:
            errors.append({"type": "invalid_handoff", "message": "handoffлҠ” none лҳҗлҠ” result_refм—¬м•ј н•©лӢҲлӢӨ.", "key": key, "step_id": step_id})
        if handoff == "result_ref":
            source_tool = str(_dict(by_id.get(dependencies[0] if len(dependencies) == 1 else "")).get("tool_name") or "")
            if (
                len(dependencies) != 1
                or source_tool != "run_data_analysis"
                or tool_name not in {"run_data_analysis", "run_visualization"}
            ):
                errors.append({"type": "invalid_result_ref_contract", "message": "result_refлҠ” лӢЁмқј run_data_analysis кІ°кіјлҘј лӢӨмқҢ run_data_analysis лҳҗлҠ” run_visualizationм—җ м „лӢ¬н•  л•Ңл§Ң мӮ¬мҡ©н•  мҲҳ мһҲмҠөлӢҲлӢӨ.", "key": key, "step_id": step_id})
        if str(step.get("on_error") or "") not in {"stop", "continue"}:
            errors.append({"type": "invalid_on_error", "message": "on_errorлҠ” stop лҳҗлҠ” continueм—¬м•ј н•©лӢҲлӢӨ.", "key": key, "step_id": step_id})
        if index == 0 and (dependencies or handoff != "none"):
            errors.append({"type": "invalid_first_step", "message": "мІ« лӢЁкі„м—җлҠ” dependencyлӮҳ result_ref handoffлҘј м§Җм •н•  мҲҳ м—ҶмҠөлӢҲлӢӨ.", "key": key, "step_id": step_id})
        seen.add(step_id)
        by_id[step_id] = step
    payload_bytes = len(json.dumps(payload, ensure_ascii=False, separators=(",", ":")).encode("utf-8"))
    if payload_bytes > MAX_WORKFLOW_PAYLOAD_BYTES:
        errors.append({"type": "workflow_payload_too_large", "message": f"Workflow Skill payloadлҠ” UTF-8 {MAX_WORKFLOW_PAYLOAD_BYTES}л°”мқҙнҠёлҘј мҙҲкіјн•  мҲҳ м—ҶмҠөлӢҲлӢӨ.", "key": key, "payload_bytes": payload_bytes})
    return errors


# н•ЁмҲҳ м„ӨлӘ…: `_dry_run_result()`лҠ” мӨ‘ліө м •мұ…м—җ л”°лқј мӢӨм ң м ҖмһҘ мӢң мҲҳн–үлҗ  н•ң кұҙмқҳ operationмқ„ кі„мӮ°н•©лӢҲлӢӨ.
def _dry_run_result(payload: dict[str, Any], action: str) -> dict[str, Any]:
    item = _dict(_list(payload.get("items"))[0])
    requested_key = str(item.get("key") or "")
    resolution = _match_resolution(payload)
    existing = _dict(resolution.get("existing_item"))
    target_key = str(existing.get("key") or requested_key) if existing and action != "create_new" else requested_key
    operation = _operation(action, bool(existing))
    record = _operation_record(requested_key, target_key, operation, existing, str(resolution.get("match_type") or ""))
    would_save = 0 if operation == "skipped" else 1
    return {
        "success": True,
        "ready_to_save": True,
        "status": "dry_run",
        "dry_run": True,
        "saved_count": 0,
        "would_save_count": would_save,
        "skipped_count": 1 - would_save,
        "operation_by_key": [record],
        "message": "л“ңлқјмқҙлҹ°мһ…лӢҲлӢӨ. MongoDBм—җлҠ” м ҖмһҘн•ҳм§Җ м•Ҡм•ҳмҠөлӢҲлӢӨ.",
        "keys": [target_key],
        "errors": [],
    }


# н•ЁмҲҳ м„ӨлӘ…: `_write_to_mongodb()`лҠ” preflightлЎң canonical лҢҖмғҒмқ„ мһ¬нҷ•мқён•ң л’Ө лӢЁкұҙ Workflow л¬ём„ңлҘј м ҖмһҘн•©лӢҲлӢӨ.
def _write_to_mongodb(payload: dict[str, Any], action: str, mongo_uri: str, mongo_database: str, collection_name: str) -> dict[str, Any]:
    uri = str(mongo_uri or "").strip()
    database = str(mongo_database or DEFAULT_DATABASE).strip() or DEFAULT_DATABASE
    collection_name = str(collection_name or DEFAULT_COLLECTION).strip() or DEFAULT_COLLECTION
    if not uri:
        return {"success": False, "ready_to_save": False, "status": "error", "saved_count": 0, "message": "MongoDB м—°кІ° URIк°Җ м—Ҷм–ҙ м ҖмһҘн•ҳм§Җ м•Ҡм•ҳмҠөлӢҲлӢӨ.", "errors": [{"type": "missing_mongo_config", "message": "mongo_uriк°Җ н•„мҡ”н•©лӢҲлӢӨ."}]}
    client = None
    try:
        client = getattr(import_module("pymongo"), "MongoClient")(uri, serverSelectionTimeoutMS=5000)
        collection = client[database][collection_name]
        item = deepcopy(_dict(_list(payload.get("items"))[0]))
        requested_key = str(item.get("key") or "")
        resolution = _match_resolution(payload)
        if resolution["status"] == "ambiguous" and action != "create_new":
            return _write_error("ambiguous_replace_target", "мң мӮ¬ лҢҖмғҒмқҙ м—¬лҹ¬ кұҙмқҙлқј м ҖмһҘн•ҳм§Җ м•Ҡм•ҳмҠөлӢҲлӢӨ.", database, collection_name, resolution.get("candidate_keys", []))
        existing = _dict(resolution.get("existing_item"))
        if existing and action != "create_new":
            target_key = str(existing.get("key") or requested_key)
            target_id = str(existing.get("_id") or f"workflow:{target_key}")
            current = _dict(collection.find_one({"_id": target_id}))
            if not current:
                return _write_error("target_disappeared", "мң мӮ¬ лҢҖмғҒмңјлЎң нҷ•м •н•ң кё°мЎҙ Workflow Skillмқҙ м ҖмһҘ м§Ғм „м—җ мӮ¬лқјмЎҢмҠөлӢҲлӢӨ.", database, collection_name, [target_key])
            existing = current
        else:
            exact = _dict(collection.find_one({"_id": f"workflow:{requested_key}"}))
            existing = exact if exact and action != "create_new" else {}
            target_key = str(existing.get("key") or requested_key)
            target_id = str(existing.get("_id") or f"workflow:{target_key}")
        if action == "create_new":
            target_key = _next_key(collection, requested_key)
            target_id = f"workflow:{target_key}"
            existing = {}
        operation = _operation(action, bool(existing))
        if operation == "skipped":
            record = _operation_record(requested_key, target_key, operation, existing, str(resolution.get("match_type") or ""))
            return {"success": True, "ready_to_save": True, "status": "skipped", "saved_count": 0, "skipped_count": 1, "operation_by_key": [record], "database": database, "collection_name": collection_name, "message": "мң мӮ¬н•ң кё°мЎҙ Workflow Skillмқ„ мң м§Җн–ҲмҠөлӢҲлӢӨ.", "errors": []}
        if operation == "merged":
            document = _deep_merge(existing, item)
        else:
            document = deepcopy(item)
        document = {
            "_id": target_id,
            "section": SECTION,
            "key": target_key,
            "status": str(document.get("status") or "active"),
            "payload": deepcopy(_dict(document.get("payload"))),
            "updated_at": datetime.now(timezone.utc).isoformat(),
            "registration_trace": {"raw_text": _redact_raw_text(str(_dict(payload.get("request")).get("raw_text") or ""))},
        }
        write_result = collection.replace_one({"_id": target_id}, document, upsert=not bool(existing))
        if existing and getattr(write_result, "matched_count", 1) != 1:
            raise RuntimeError(f"target document was not matched: {target_id}")
        record = _operation_record(requested_key, target_key, operation, existing, str(resolution.get("match_type") or ""))
        return {"success": True, "ready_to_save": True, "status": "saved", "saved_count": 1, "skipped_count": 0, "operation_by_key": [record], "database": database, "collection_name": collection_name, "message": "Workflow Skill м ҖмһҘмқ„ мҷ„лЈҢн–ҲмҠөлӢҲлӢӨ.", "errors": []}
    except Exception as exc:
        return {"success": False, "ready_to_save": False, "status": "error", "saved_count": 0, "database": database, "collection_name": collection_name, "message": "MongoDB м ҖмһҘ мӨ‘ мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ.", "errors": [{"type": "mongo_write_error", "message": str(exc)}]}
    finally:
        if client is not None:
            client.close()


# н•ЁмҲҳ м„ӨлӘ…: `_match_resolution()`мқҖ similarity кІ°кіјлҘј м ҖмһҘ к°ҖлҠҘн•ң мң мқј лҢҖмғҒВ·лҜёмқјм№ҳВ·лӘЁнҳён•Ё мӨ‘ н•ҳлӮҳлЎң нҷ•м •н•©лӢҲлӢӨ.
def _match_resolution(payload: dict[str, Any]) -> dict[str, Any]:
    matches = [_dict(match) for match in _list(payload.get("existing_matches"))]
    if any(match.get("identity_resolution") == "ambiguous" for match in matches):
        candidates = []
        for match in matches:
            candidates.extend(_list(match.get("existing_candidate_keys")))
        return {"status": "ambiguous", "candidate_keys": list(dict.fromkeys(str(value) for value in candidates if str(value).strip()))}
    resolved = [match for match in matches if isinstance(match.get("existing_item"), dict)]
    if len(resolved) > 1:
        return {"status": "ambiguous", "candidate_keys": [str(match.get("existing_key") or "") for match in resolved]}
    if not resolved:
        return {"status": "not_found", "candidate_keys": []}
    match = resolved[0]
    return {"status": "unique", "existing_item": deepcopy(_dict(match.get("existing_item"))), "match_type": str(match.get("match_type") or "")}


# н•ЁмҲҳ м„ӨлӘ…: `_operation()`мқҖ мӨ‘ліө actionкіј кё°мЎҙ л¬ём„ң мЎҙмһ¬ м—¬л¶ҖлҘј мӢӨм ң м ҖмһҘ operation мқҙлҰ„мңјлЎң ліҖнҷҳн•©лӢҲлӢӨ.
def _operation(action: str, has_existing: bool) -> str:
    if action == "create_new":
        return "created_new"
    if has_existing and action == "skip":
        return "skipped"
    if has_existing and action == "merge":
        return "merged"
    if has_existing and action == "replace":
        return "replaced"
    return "inserted"


# н•ЁмҲҳ м„ӨлӘ…: `_operation_record()`лҠ” мҡ”мІӯ keyмҷҖ мӢӨм ң canonical targetмқ„ м ҖмһҘ кІ°кіјм—җ н•Ёк»ҳ кё°лЎқн•©лӢҲлӢӨ.
def _operation_record(requested_key: str, target_key: str, operation: str, existing: dict[str, Any], match_type: str) -> dict[str, Any]:
    record = {"key": target_key, "operation": operation, "target_key": target_key, "target_id": str(existing.get("_id") or f"workflow:{target_key}")}
    if requested_key != target_key:
        record["requested_key"] = requested_key
    if match_type:
        record["match_type"] = match_type
    return record


# н•ЁмҲҳ м„ӨлӘ…: `_next_key()`лҠ” create_new м •мұ…м—җм„ң м¶©лҸҢн•ҳм§Җ м•ҠлҠ” `_copy` suffix keyлҘј кі„мӮ°н•©лӢҲлӢӨ.
def _next_key(collection: Any, key: str) -> str:
    if not collection.find_one({"_id": f"workflow:{key}"}):
        return key
    base = f"{key}_copy"
    candidate = base
    index = 2
    while collection.find_one({"_id": f"workflow:{candidate}"}):
        candidate = f"{base}_{index}"
        index += 1
    return candidate


# н•ЁмҲҳ м„ӨлӘ…: `_deep_merge()`лҠ” мғҲ Workflow н•„л“ңл§Ң кё°мЎҙ л¬ём„ңм—җ мһ¬к·Җ лі‘н•©н•ҳкі  лӮҙл¶Җ IDлҠ” мң м§Җн•©лӢҲлӢӨ.
def _deep_merge(existing: dict[str, Any], incoming: dict[str, Any]) -> dict[str, Any]:
    merged = deepcopy(existing)
    for key, value in incoming.items():
        if key in {"_id", "updated_at", "registration_trace"}:
            continue
        if isinstance(value, dict) and isinstance(merged.get(key), dict):
            merged[key] = _deep_merge(merged[key], value)
        elif isinstance(value, list) and isinstance(merged.get(key), list):
            combined = deepcopy(merged[key])
            for item in value:
                if item not in combined:
                    combined.append(deepcopy(item))
            merged[key] = combined
        else:
            merged[key] = deepcopy(value)
    return merged


# н•ЁмҲҳ м„ӨлӘ…: `_write_error()`лҠ” preflight м ҖмһҘ м°ЁлӢЁ мҳӨлҘҳлҘј кіөнҶө write_result кі„м•ҪмңјлЎң л§Ңл“ӯлӢҲлӢӨ.
def _write_error(error_type: str, message: str, database: str, collection: str, candidate_keys: Any) -> dict[str, Any]:
    return {"success": False, "ready_to_save": False, "status": "error", "saved_count": 0, "database": database, "collection_name": collection, "message": message, "errors": [{"type": error_type, "message": message, "existing_candidate_keys": deepcopy(_list(candidate_keys))}]}


# н•ЁмҲҳ м„ӨлӘ…: `_secret_paths()`лҠ” Workflow нӣ„ліҙ м „мІҙм—җм„ң credentialлЎң мқҳмӢ¬лҗҳлҠ” field кІҪлЎңлҘј мһ¬к·Җ нғҗмғүн•©лӢҲлӢӨ.
def _secret_paths(value: Any, prefix: str = "") -> list[str]:
    paths = []
    if isinstance(value, dict):
        for key, item in value.items():
            path = f"{prefix}.{key}" if prefix else str(key)
            normalized = re.sub(r"[^a-z0-9]+", "_", str(key).lower())
            if any(pattern in normalized for pattern in SECRET_PATTERNS):
                paths.append(path)
            else:
                paths.extend(_secret_paths(item, path))
    elif isinstance(value, list):
        for index, item in enumerate(value):
            paths.extend(_secret_paths(item, f"{prefix}[{index}]"))
    return paths


# н•ЁмҲҳ м„ӨлӘ…: `_redact_raw_text()`лҠ” л“ұлЎқ мӣҗл¬ём—җ нҸ¬н•Ёлҗ  мҲҳ мһҲлҠ” credential к°’мқ„ traceм—җ лӮЁкё°кё° м „м—җ л§ҲмҠӨнӮ№н•©лӢҲлӢӨ.
def _redact_raw_text(value: str, limit: int = 2000) -> str:
    pattern = re.compile(r"(?i)(password|passwd|token|secret|api[_-]?key|authorization|credential)([\"']?\s*[:=]\s*[\"']?)([^\s,;\"'}]+)")
    return pattern.sub(r"\1\2***", str(value or ""))[:limit]


# н•ЁмҲҳ м„ӨлӘ…: `_duplicate_action()`мқҖ мҡ”мІӯм—җ м§Җм •лҗң мӨ‘ліө м •мұ…мқ„ н—Ҳмҡ© лӘ©лЎқмңјлЎң м ңн•ңн•©лӢҲлӢӨ.
def _duplicate_action(payload: dict[str, Any]) -> str:
    action = str(_dict(payload.get("request")).get("duplicate_action") or "skip").strip().lower()
    return action if action in ALLOWED_ACTIONS else "skip"


# н•ЁмҲҳ м„ӨлӘ…: `_unique_errors()`лҠ” лҸҷмқјн•ң мҳӨлҘҳлҘј л°ңмғқ мҲңм„ңлҢҖлЎң н•ң кұҙм”©л§Ң мң м§Җн•©лӢҲлӢӨ.
def _unique_errors(values: list[Any]) -> list[dict[str, Any]]:
    result = []
    seen = set()
    for value in values:
        item = value if isinstance(value, dict) else {"type": "review_error", "message": str(value)}
        marker = (item.get("type"), item.get("key"), item.get("step_id"), item.get("field"), item.get("message"))
        if marker not in seen:
            seen.add(marker)
            result.append(deepcopy(item))
    return result


# н•ЁмҲҳ м„ӨлӘ…: `_payload()`лҠ” Langflow Data лҳҗлҠ” dictм—җм„ң ліҖкІҪм—җ м•Ҳм „н•ң ліөмӮ¬ліёмқ„ кәјлғ…лӢҲлӢӨ.
def _payload(value: Any) -> dict[str, Any]:
    data = getattr(value, "data", value)
    return deepcopy(data) if isinstance(data, dict) else {}


# н•ЁмҲҳ м„ӨлӘ…: `_dict()`лҠ” к°’мқҙ dictмқј л•Ңл§Ң л°ҳнҷҳн•ҳкі  м•„лӢҲл©ҙ л№Ҳ dictлҘј мӮ¬мҡ©н•©лӢҲлӢӨ.
def _dict(value: Any) -> dict[str, Any]:
    return value if isinstance(value, dict) else {}


# н•ЁмҲҳ м„ӨлӘ…: `_list()`лҠ” к°’мқҙ listмқј л•Ңл§Ң л°ҳнҷҳн•ҳкі  м•„лӢҲл©ҙ л№Ҳ лӘ©лЎқмқ„ мӮ¬мҡ©н•©лӢҲлӢӨ.
def _list(value: Any) -> list[Any]:
    return value if isinstance(value, list) else []


# Langflow м»ҙнҸ¬л„ҢнҠё нҒҙлһҳмҠӨ: кІ°м •лЎ м Ғ кІҖмҲҳмҷҖ standalone MongoDB м ҖмһҘмқ„ н•ҳлӮҳмқҳ Writer нҸ¬нҠёлЎң м ңкіөн•©лӢҲлӢӨ.
class WorkflowSkillReviewWriter(Component):
    display_name = "07 Workflow Skill кІҖмҲҳ/м ҖмһҘ мІҳлҰ¬кё°"
    description = "Workflow кі„м•Ҫкіј мң мӮ¬ лҢҖмғҒмқ„ мһ¬кІҖмҰқн•ң л’Ө dry-run лҳҗлҠ” MongoDB м ҖмһҘмқ„ мҲҳн–үн•©лӢҲлӢӨ."
    inputs = [
        DataInput(name="payload", display_name="нҺҳмқҙлЎңл“ң", required=True),
        MessageTextInput(name="mongo_uri", display_name="MongoDB м—°кІ° URI", required=False, value=""),
        MessageTextInput(name="mongo_database", display_name="MongoDB лҚ°мқҙн„°лІ мқҙмҠӨ", required=False, value=DEFAULT_DATABASE),
        MessageTextInput(name="collection_name", display_name="м»¬л үм…ҳ мқҙлҰ„", required=False, value=DEFAULT_COLLECTION),
    ]
    outputs = [Output(name="payload_out", display_name="нҺҳмқҙлЎңл“ң м¶ңл Ҙ", method="build_payload", types=["Data"])]

    # Langflow м¶ңл Ҙ н•ЁмҲҳ: нҳ„мһ¬ кІҖмҲҳ кІ°кіјмҷҖ м ҖмһҘ кІ°кіјк°Җ нҸ¬н•Ёлҗң нҺҳмқҙлЎңл“ңлҘј л°ҳнҷҳн•©лӢҲлӢӨ.
    def build_payload(self) -> Data:
        return Data(
            data=review_and_write(
                getattr(self, "payload", None),
                "",
                getattr(self, "mongo_uri", ""),
                getattr(self, "mongo_database", DEFAULT_DATABASE),
                getattr(self, "collection_name", DEFAULT_COLLECTION),
            )
        )

