from __future__ import annotations

from copy import deepcopy
from typing import Any

from lfx.custom.custom_component.component import Component
from lfx.io import DataInput, Output
from lfx.schema.data import Data


# мЈјмҡ” н•ЁмҲҳ: лӮҙл¶Җ Workflow Skill м ҖмһҘ нҺҳмқҙлЎңл“ңлҘј мӮ¬мҡ©мһҗ мқ‘лӢөмҡ© compact кі„м•ҪмңјлЎң ліҖнҷҳн•©лӢҲлӢӨ.
def build_response(payload_value: Any) -> dict[str, Any]:
    payload = _payload(payload_value)
    write_result = _dict(payload.get("write_result"))
    review = _dict(payload.get("review"))
    items = [_dict(item) for item in _list(payload.get("items")) if isinstance(item, dict)]
    status = _status(write_result, review)
    rows = [_row(item, write_result) for item in items]
    message = _headline(status, write_result)
    return {
        "metadata_type": "workflow_skill",
        "metadata_label": "Workflow Skill",
        "status": status,
        "success": status in {"dry_run", "saved", "skipped"},
        "message": message,
        "answer_message": message,
        "answer_sections": {
            "summary": {"headline": message},
            "key_points": _key_points(items, write_result),
            "target_table": {
                "title": "л“ұлЎқ лҢҖмғҒ Workflow Skill",
                "columns": ["Workflow Key", "н‘ңмӢң мқҙлҰ„", "лӢЁкі„ мҲҳ", "мӢӨн–ү Tool", "мІҳлҰ¬"],
                "rows": rows,
                "display_limit": 5,
            },
            "workflow_steps": _step_sections(items),
            "notices": _notices(review, write_result, payload),
            "next_steps": _next_steps(status),
        },
        "data": {"columns": ["Workflow Key", "н‘ңмӢң мқҙлҰ„", "лӢЁкі„ мҲҳ", "мӢӨн–ү Tool", "мІҳлҰ¬"], "rows": rows, "row_count": len(rows)},
        "metadata_authoring": {
            "requested_action": str(_dict(payload.get("request")).get("duplicate_action") or "skip"),
            "dry_run": bool(write_result.get("dry_run", _dict(payload.get("request")).get("dry_run", True))),
            "keys": [str(item.get("key") or "") for item in items],
            "workflow_steps": _step_sections(items),
        },
        "write_result": _compact_write_result(write_result),
        "trace": {"workflow_contract": deepcopy(_dict(_dict(payload.get("trace")).get("workflow_contract")))},
    }


# н•ЁмҲҳ м„ӨлӘ…: `_status()`лҠ” Writer кІ°кіјмҷҖ review мғҒнғңлҘј мҷёл¶Җ мқ‘лӢөмқҳ кі м • мғҒнғңлЎң ліҖнҷҳн•©лӢҲлӢӨ.
def _status(write_result: dict[str, Any], review: dict[str, Any]) -> str:
    if write_result.get("dry_run") and write_result.get("success"):
        return "dry_run"
    status = str(write_result.get("status") or "")
    if status in {"saved", "skipped", "needs_input", "error", "partial_success"}:
        return status
    if _list(review.get("supplement_requests")):
        return "needs_input"
    return "error" if write_result.get("success") is False else "unknown"


# н•ЁмҲҳ м„ӨлӘ…: `_headline()`мқҖ мғҒнғңлі„ л“ұлЎқ кІ°кіјлҘј н•ң л¬ёмһҘмңјлЎң мҡ”м•Ҫн•©лӢҲлӢӨ.
def _headline(status: str, write_result: dict[str, Any]) -> str:
    if status == "dry_run":
        return f"Workflow Skill {int(write_result.get('would_save_count') or 0)}кұҙмқҳ м ҖмһҘ кі„нҡҚмқ„ нҷ•мқён–ҲмҠөлӢҲлӢӨ."
    if status == "saved":
        return f"Workflow Skill {int(write_result.get('saved_count') or 0)}кұҙмқ„ м ҖмһҘн–ҲмҠөлӢҲлӢӨ."
    if status == "skipped":
        return "мң мӮ¬н•ң кё°мЎҙ Workflow Skillмқ„ мң м§Җн•ҳкі  м ҖмһҘмқ„ кұҙл„Ҳлӣ°м—ҲмҠөлӢҲлӢӨ."
    if status == "needs_input":
        return "Workflow Skillмқ„ нҷ•м •н•ҳл Өл©ҙ мһ…л Ҙ м •ліҙлҘј ліҙмҷ„н•ҙм•ј н•©лӢҲлӢӨ."
    if status == "partial_success":
        return "Workflow Skill м ҖмһҘмқҙ мқјл¶Җл§Ң мҷ„лЈҢлҗҳм—ҲмҠөлӢҲлӢӨ."
    return str(write_result.get("message") or "Workflow Skill м ҖмһҘмқ„ мҷ„лЈҢн•ҳм§Җ лӘ»н–ҲмҠөлӢҲлӢӨ.")


# н•ЁмҲҳ м„ӨлӘ…: `_row()`лҠ” Workflow нӣ„ліҙмҷҖ operationмқ„ мӮ¬мҡ©мһҗ н‘ңмқҳ н•ң н–үмңјлЎң ліҖнҷҳн•©лӢҲлӢӨ.
def _row(item: dict[str, Any], write_result: dict[str, Any]) -> dict[str, Any]:
    payload = _dict(item.get("payload"))
    steps = [_dict(step) for step in _list(payload.get("steps"))]
    operation = _operation_for_key(str(item.get("key") or ""), write_result)
    return {
        "Workflow Key": str(item.get("key") or ""),
        "н‘ңмӢң мқҙлҰ„": str(payload.get("display_name") or ""),
        "лӢЁкі„ мҲҳ": len(steps),
        "мӢӨн–ү Tool": " вҶ’ ".join(str(step.get("tool_name") or "") for step in steps),
        "мІҳлҰ¬": _operation_label(operation, bool(write_result.get("dry_run"))),
    }


# н•ЁмҲҳ м„ӨлӘ…: `_step_sections()`лҠ” к°Ғ лӢЁкі„мқҳ м§Ҳл¬ёВ·мқҳмЎҙм„ұВ·handoffлҘј JSON лҢҖмӢ  мқҪкё° мү¬мҡҙ мҡ”м•Ҫ лӘ©лЎқмңјлЎң л§Ңл“ӯлӢҲлӢӨ.
def _step_sections(items: list[dict[str, Any]]) -> list[dict[str, Any]]:
    result = []
    for item in items:
        payload = _dict(item.get("payload"))
        for index, step in enumerate(_list(payload.get("steps")), start=1):
            step = _dict(step)
            dependencies = ", ".join(str(value) for value in _list(step.get("depends_on"))) or "м—ҶмқҢ"
            result.append(
                {
                    "мҲңм„ң": index,
                    "лӢЁкі„": str(step.get("step_id") or ""),
                    "Tool": str(step.get("tool_name") or ""),
                    "м§Ҳл¬ё": str(step.get("question") or ""),
                    "м„ н–ү лӢЁкі„": dependencies,
                    "кІ°кіј м „лӢ¬": "м•һ лӢЁкі„ мӢӨм ң кІ°кіј мӮ¬мҡ©" if step.get("handoff") == "result_ref" else "мҲңм„ңл§Ң ліҙмһҘ",
                    "мҳӨлҘҳ м •мұ…": "мӨ‘лӢЁ" if step.get("on_error") == "stop" else "лӢӨмқҢ лӢЁкі„ кі„мҶҚ",
                }
            )
    return result


# н•ЁмҲҳ м„ӨлӘ…: `_key_points()`лҠ” мғқм„ұ нӣ„ліҙмҷҖ м ҖмһҘ кІ°кіјм—җм„ң н•ңлҲҲм—җ ліј н•өмӢ¬ кұҙмҲҳлҘј кі„мӮ°н•©лӢҲлӢӨ.
def _key_points(items: list[dict[str, Any]], write_result: dict[str, Any]) -> list[str]:
    step_count = sum(len(_list(_dict(item.get("payload")).get("steps"))) for item in items)
    return [
        f"мғқм„ұлҗң Workflow Skill нӣ„ліҙлҠ” {len(items)}кұҙмһ…лӢҲлӢӨ.",
        f"мҲңм°Ё мӢӨн–ү лӢЁкі„лҠ” мҙқ {step_count}к°ңмһ…лӢҲлӢӨ.",
        f"м ҖмһҘ мІҳлҰ¬ кІ°кіј: {_operation_summary(write_result) or str(write_result.get('message') or 'мІҳлҰ¬ кІ°кіј м—ҶмқҢ')}",
    ]


# н•ЁмҲҳ м„ӨлӘ…: `_notices()`лҠ” мҳӨлҘҳВ·ліҙмҷ„ мҡ”мІӯВ·к°Җм •мқ„ мӨ‘ліө м—ҶлҠ” мӮ¬мҡ©мһҗ м•ҲлӮҙ лӘ©лЎқмңјлЎң м •лҰ¬н•©лӢҲлӢӨ.
def _notices(review: dict[str, Any], write_result: dict[str, Any], payload: dict[str, Any]) -> list[dict[str, str]]:
    notices = []
    for error in _list(write_result.get("errors")) + _list(review.get("errors")):
        message = str(_dict(error).get("message") or error).strip()
        if message and message not in {item["message"] for item in notices}:
            notices.append({"type": "error", "title": "мҳӨлҘҳ", "message": message})
    for message in _list(review.get("supplement_requests")):
        text = str(message).strip()
        if text:
            notices.append({"type": "supplement", "title": "м¶”к°Җ нҷ•мқё н•„мҡ”", "message": text})
    for message in _list(review.get("assumptions")):
        text = str(message).strip()
        if text:
            notices.append({"type": "info", "title": "м Ғмҡ© к°Җм •", "message": text})
    if payload.get("conflict_warnings"):
        notices.append({"type": "warning", "title": "мң мӮ¬ н•ӯлӘ©", "message": f"кё°мЎҙ Workflow Skillкіј кІ№м№ҳлҠ” нӣ„ліҙ {len(_list(payload.get('conflict_warnings')))}кұҙмқ„ нҷ•мқён–ҲмҠөлӢҲлӢӨ."})
    return notices[:12]


# н•ЁмҲҳ м„ӨлӘ…: `_next_steps()`лҠ” dry-runВ·м ҖмһҘВ·мҳӨлҘҳ мғҒнғңм—җ л§һлҠ” лӢӨмқҢ мһ‘м—…мқ„ м•ҲлӮҙн•©лӢҲлӢӨ.
def _next_steps(status: str) -> list[str]:
    if status == "dry_run":
        return ["м ҖмһҘ кі„нҡҚкіј лӢЁкі„ мҲңм„ңк°Җ л§һмңјл©ҙ Dry Runмқ„ falseлЎң л°”кҝ” лӢӨмӢң мӢӨн–үн•ҳм„ёмҡ”.", "м ҖмһҘ нӣ„ 08 Workflow Orchestratorм—җм„ң intent example лҳҗлҠ” workflow keyлЎң нҳём¶ңн•ҙ ліҙм„ёмҡ”."]
    if status == "saved":
        return ["08 Workflow Orchestratorмқҳ лӢӨмқҢ мӢӨн–үм—җм„ң л“ұлЎқн•ң Workflow Skillмқ„ нҳём¶ңн•ҙ ліҙм„ёмҡ”.", "мһҳлӘ» м„ нғқлҗҳл©ҙ keywordsмҷҖ excluded_keywordsлҘј мЎ°м •н•ҳм„ёмҡ”."]
    if status == "needs_input":
        return ["нҷ•мқён•  м җмқҳ лҲ„лқҪ м •ліҙлҘј мӣҗл¬ём—җ м¶”к°Җн•ҙ лӢӨмӢң мӢӨн–үн•ҳм„ёмҡ”."]
    return ["мҳӨлҘҳ л©”мӢңм§ҖмҷҖ MongoDB standalone мһ…л Ҙк°’мқ„ нҷ•мқён•ң л’Ө лӢӨмӢң мӢӨн–үн•ҳм„ёмҡ”."]


# н•ЁмҲҳ м„ӨлӘ…: `_operation_for_key()`лҠ” нҳ„мһ¬ Workflow нӣ„ліҙм—җ лҢҖмқ‘н•ҳлҠ” Writer operationмқ„ м°ҫмҠөлӢҲлӢӨ.
def _operation_for_key(key: str, write_result: dict[str, Any]) -> str:
    operations = [_dict(item) for item in _list(write_result.get("operation_by_key"))]
    for operation in operations:
        if key in {str(operation.get("key") or ""), str(operation.get("requested_key") or "")}:
            return str(operation.get("operation") or "")
    return str(operations[0].get("operation") or "") if len(operations) == 1 else ""


# н•ЁмҲҳ м„ӨлӘ…: `_operation_label()`мқҖ лӮҙл¶Җ operation мқҙлҰ„мқ„ мһҗм—°м–ҙ мІҳлҰ¬ мғҒнғңлЎң ліҖнҷҳн•©лӢҲлӢӨ.
def _operation_label(operation: str, dry_run: bool) -> str:
    labels = {"inserted": "мӢ к·ң м ҖмһҘ", "replaced": "кё°мЎҙ Skill көҗмІҙ", "merged": "кё°мЎҙ Skill лі‘н•©", "skipped": "кё°мЎҙ Skill мң м§Җ", "created_new": "мғҲ KeyлЎң м ҖмһҘ"}
    label = labels.get(operation, "мІҳлҰ¬ м•Ҳ н•Ё" if not operation else operation)
    return f"{label} мҳҲм •" if dry_run and operation != "skipped" else label


# н•ЁмҲҳ м„ӨлӘ…: `_operation_summary()`лҠ” Writer operationлі„ кұҙмҲҳлҘј н•ң л¬ёмһҘмңјлЎң мҡ”м•Ҫн•©лӢҲлӢӨ.
def _operation_summary(write_result: dict[str, Any]) -> str:
    counts = {}
    for item in _list(write_result.get("operation_by_key")):
        operation = str(_dict(item).get("operation") or "")
        if operation:
            label = _operation_label(operation, bool(write_result.get("dry_run")))
            counts[label] = counts.get(label, 0) + 1
    return ", ".join(f"{label} {count}кұҙ" for label, count in counts.items())


# н•ЁмҲҳ м„ӨлӘ…: `_compact_write_result()`лҠ” мҷёл¶Җ мқ‘лӢөм—җ н•„мҡ”н•ң м ҖмһҘ мғҒнғңВ·operationВ·мҳӨлҘҳл§Ң лӮЁк№ҒлӢҲлӢӨ.
def _compact_write_result(write_result: dict[str, Any]) -> dict[str, Any]:
    allowed = {"success", "ready_to_save", "status", "dry_run", "saved_count", "would_save_count", "skipped_count", "operation_by_key", "database", "collection_name", "message", "errors", "keys"}
    return {key: deepcopy(value) for key, value in write_result.items() if key in allowed}


# н•ЁмҲҳ м„ӨлӘ…: `_payload()`лҠ” Langflow Data лҳҗлҠ” dictм—җм„ң ліҖкІҪм—җ м•Ҳм „н•ң ліөмӮ¬ліёмқ„ кәјлғ…лӢҲлӢӨ.
def _payload(value: Any) -> dict[str, Any]:
    data = getattr(value, "data", value)
    return deepcopy(data) if isinstance(data, dict) else {}


# н•ЁмҲҳ м„ӨлӘ…: `_dict()`лҠ” к°’мқҙ dictмқј л•Ңл§Ң л°ҳнҷҳн•ҳкі  м•„лӢҲл©ҙ л№Ҳ dictлҘј мӮ¬мҡ©н•©лӢҲлӢӨ.
def _dict(value: Any) -> dict[str, Any]:
    return value if isinstance(value, dict) else {}


# н•ЁмҲҳ м„ӨлӘ…: `_list()`лҠ” к°’мқҙ listмқј л•Ңл§Ң л°ҳнҷҳн•ҳкі  м•„лӢҲл©ҙ л№Ҳ лӘ©лЎқмқ„ мӮ¬мҡ©н•©лӢҲлӢӨ.
def _list(value: Any) -> list[Any]:
    return value if isinstance(value, list) else []


# Langflow м»ҙнҸ¬л„ҢнҠё нҒҙлһҳмҠӨ: Writer кІ°кіјлҘј лӢЁмқј кө¬мЎ°нҷ” мқ‘лӢө нҸ¬нҠёлЎң м ңкіөн•©лӢҲлӢӨ.
class WorkflowSkillSavingResponseBuilder(Component):
    display_name = "08 Workflow Skill л“ұлЎқ мқ‘лӢө м •к·ңнҷ”кё°"
    description = "Workflow Skill кІҖмҲҳВ·м ҖмһҘ кІ°кіјлҘј мұ„нҢ…кіј APIк°Җ кіөмң н•  compact мқ‘лӢөмңјлЎң ліҖнҷҳн•©лӢҲлӢӨ."
    inputs = [DataInput(name="payload", display_name="нҺҳмқҙлЎңл“ң", required=True)]
    outputs = [Output(name="payload_out", display_name="нҺҳмқҙлЎңл“ң м¶ңл Ҙ", method="build_payload", types=["Data"])]

    # Langflow м¶ңл Ҙ н•ЁмҲҳ: нҳ„мһ¬ м ҖмһҘ кІ°кіјлҘј мӮ¬мҡ©мһҗ мқ‘лӢөмҡ© DataлЎң л°ҳнҷҳн•©лӢҲлӢӨ.
    def build_payload(self) -> Data:
        return Data(data=build_response(getattr(self, "payload", None)))

